import "./styles/History.css";
import { useEffect, useState } from "react";

function HistoryByCategory() {
  const [history, setHistory] = useState({});

  useEffect(() => {
    const borrowed = JSON.parse(localStorage.getItem("borrowedBooks")) || [];
    const wishlist = JSON.parse(localStorage.getItem("wishlist")) || [];

    const result = {};

    borrowed.forEach((book) => {
      if (!book.genre) return;
      if (!result[book.genre]) {
        result[book.genre] = { borrowed: 0, wishlisted: 0 };
      }
      result[book.genre].borrowed += 1;
    });

    wishlist.forEach((book) => {
      if (!book.genre) return;
      if (!result[book.genre]) {
        result[book.genre] = { borrowed: 0, wishlisted: 0 };
      }
      result[book.genre].wishlisted += 1;
    });

    setHistory(result);
  }, []);

  return (
    <div className="books-page">
      <h1 className="books-title">History by Category</h1>

      {Object.keys(history).length === 0 ? (
        <p>No activity yet.</p>
      ) : (
        <div className="history-grid">
          {Object.entries(history).map(([genre, data]) => (
            <div key={genre} className="history-card">
              <h3>{genre}</h3>
              <p>📚 Borrowed: {data.borrowed}</p>
              <p>❤️ Wishlisted: {data.wishlisted}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default HistoryByCategory;
